package com.example.steps;

import com.example.domain.shared.DomainEvent;
import com.example.domain.validation.model.DefectReportedEvent;
import com.example.domain.validation.model.ReportDefectCmd;
import com.example.domain.validation.model.ValidationAggregate;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;

import java.util.Map;

import static org.junit.jupiter.api.Assertions.*;

/**
 * Cucumber Steps for S-FB-1: Validating VW-454.
 * Verifies that the Slack body generated by the Validation aggregate contains the GitHub URL.
 */
public class VW454Steps {

    private ValidationAggregate aggregate;
    private Exception caughtException;
    private DefectReportedEvent resultEvent;

    @Given("a defect report command for VW-454")
    public void a_defect_report_command_for_vw_454() {
        aggregate = new ValidationAggregate("vw-454-defect-1");
    }

    @When("the command is executed with a valid GitHub URL")
    public void the_command_is_executed_with_a_valid_github_url() {
        ReportDefectCmd cmd = new ReportDefectCmd(
                "vw-454-defect-1",
                "21b76fa6-afb6-4593-9e1b-b5d7548ac4d1",
                "Fix: Validating VW-454 — GitHub URL in Slack body",
                "LOW",
                "https://github.com/org/repo/issues/454",
                Map.of("component", "validation")
        );
        try {
            var events = aggregate.execute(cmd);
            resultEvent = (DefectReportedEvent) events.get(0);
        } catch (Exception e) {
            caughtException = e;
        }
    }

    @Then("the resulting event should contain the GitHub URL in the Slack body")
    public void the_resulting_event_should_contain_the_github_url_in_the_slack_body() {
        assertNotNull(resultEvent, "Event should not be null");
        String body = resultEvent.slackBody();
        assertNotNull(body, "Slack body should not be null");
        
        // The core assertion for VW-454
        assertTrue(body.contains("https://github.com/org/repo/issues/454"), 
                "Slack body should contain the GitHub URL: " + body);
        assertTrue(body.contains("GitHub Issue"), 
                "Slack body should mention 'GitHub Issue': " + body);
    }

    @When("the command is executed with a malformed URL")
    public void the_command_is_executed_with_a_malformed_url() {
        ReportDefectCmd cmd = new ReportDefectCmd(
                "vw-454-bad",
                "p-1",
                "Bad Defect",
                "HIGH",
                "http://evil.com", // Not github.com
                Map.of()
        );
        try {
            aggregate.execute(cmd);
        } catch (IllegalArgumentException e) {
            caughtException = e;
        }
    }

    @Then("validation should fail with an error")
    public void validation_should_fail_with_an_error() {
        assertNotNull(caughtException, "Expected an exception for bad URL");
        assertTrue(caughtException.getMessage().contains("githubUrl"));
    }
}
